mapper.sql:
WHERE a.deleted_at IS NULL
AND a.status = #{status}
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.slug LIKE CONCAT('%', #{keyword}, '%'))

mapper.select:
SELECT EXISTS(
    SELECT 1 FROM article
    WHERE slug = #{slug}
    AND id != #{excludeId}
)

mapper.insert:
